        uniffiFree: { (uniffiHandle: UInt64) -> () in
            do {
                try FfiConverterTypeNetworkInterface.handleMap.remove(handle: uniffiHandle)
            } catch {
                print("Uniffi callback interface NetworkInterface: handle missing in uniffiFree")
            }
        },
        uniffiClone: { (uniffiHandle: UInt64) -> UInt64 in
            do {
                return try FfiConverterTypeNetworkInterface.handleMap.clone(handle: uniffiHandle)
            } catch {
                fatalError("Uniffi callback interface NetworkInterface: handle missing in uniffiClone")
            }
        },
        send: { (
            uniffiHandle: UInt64,
            data: RustBuffer,
            uniffiFutureCallback: @escaping UniffiForeignFutureCompleteVoid,
            uniffiCallbackData: UInt64,
            uniffiOutDroppedCallback: UnsafeMutablePointer<UniffiForeignFutureDroppedCallbackStruct>
        ) in
