public struct FfiConverterTypeNetworkInterface: FfiConverter {
    fileprivate static let handleMap = UniffiHandleMap<NetworkInterface>()

    typealias FfiType = UInt64
    typealias SwiftType = NetworkInterface

    public static func lift(_ handle: UInt64) throws -> NetworkInterface {
        if ((handle & 1) == 0) {
            // Rust-generated handle, construct a new class that uses the handle to implement the
            // interface
            return NetworkInterfaceImpl(unsafeFromHandle: handle)
        } else {
            // Swift-generated handle, get the object from the handle map
            return try handleMap.remove(handle: handle)
        }
    }

    public static func lower(_ value: NetworkInterface) -> UInt64 {
         if let rustImpl = value as? NetworkInterfaceImpl {
             // Rust-implemented object.  Clone the handle and return it
            return rustImpl.uniffiCloneHandle()
         } else {
            // Swift object, generate a new vtable handle and return that.
            return handleMap.insert(obj: value)
         }
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> NetworkInterface {
        let handle: UInt64 = try readInt(&buf)
        return try lift(handle)
    }

    public static func write(_ value: NetworkInterface, into buf: inout [UInt8]) {
        writeInt(&buf, lower(value))
    }
}


