        case 1: return .waitForSetup
        
        case 2: return .waitForSigs
        
        case 3: return .waitForDevices
        
        case 4: return .ready
        
        case 5: return .running
        
        case 6: return .finished
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

