public enum GeneralError: Swift.Error, Equatable, Hashable, Foundation.LocalizedError {

    
    
    case InvalidInput(String
    )
    case InvalidState(String
    )
    case SignatureError(String
    )
    case InvalidSetupMessage
    case MessageSendError
    case KeygenError(String
    )
    case AbortProtocol(UInt32
    )
    case AbortProtocolAndBanParty(UInt8
    )
    case SigningError(String
    )
    case InvalidContext
    case Generic
    case Cancelled

    

    
    public var errorDescription: String? {
        String(reflecting: self)
    }
    
}

