@_documentation(visibility: private)
#endif
public struct FfiConverterTypeGeneralError: FfiConverterRustBuffer {
    typealias SwiftType = GeneralError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> GeneralError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .InvalidInput(
            try FfiConverterString.read(from: &buf)
            )
        case 2: return .InvalidState(
            try FfiConverterString.read(from: &buf)
            )
        case 3: return .SignatureError(
            try FfiConverterString.read(from: &buf)
            )
        case 4: return .InvalidSetupMessage
        case 5: return .MessageSendError
        case 6: return .KeygenError(
            try FfiConverterString.read(from: &buf)
            )
        case 7: return .AbortProtocol(
            try FfiConverterUInt32.read(from: &buf)
            )
        case 8: return .AbortProtocolAndBanParty(
            try FfiConverterUInt8.read(from: &buf)
            )
        case 9: return .SigningError(
            try FfiConverterString.read(from: &buf)
            )
        case 10: return .InvalidContext
        case 11: return .Generic
        case 12: return .Cancelled

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: GeneralError, into buf: inout [UInt8]) {
        switch value {

        

        
        
        case let .InvalidInput(v1):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(v1, into: &buf)
            
        
        case let .InvalidState(v1):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(v1, into: &buf)
            
        
        case let .SignatureError(v1):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(v1, into: &buf)
            
        
        case .InvalidSetupMessage:
            writeInt(&buf, Int32(4))
        
        
        case .MessageSendError:
