        case let .AbortProtocolAndBanParty(v1):
            writeInt(&buf, Int32(8))
            FfiConverterUInt8.write(v1, into: &buf)
            
        
        case let .SigningError(v1):
            writeInt(&buf, Int32(9))
            FfiConverterString.write(v1, into: &buf)
            
        
        case .InvalidContext:
            writeInt(&buf, Int32(10))
        
        
        case .Generic:
